// Caoren Cup web visual modification modules
// Generated by phase2_fix_full_caoren_module_params.js
// Keep command grammar aligned with game-plugin/Features/*Feature.cs.

export type CaorenModParamType = 'select' | 'number' | 'text' | 'boolean';

export type CaorenModOption = { label: string; value: string | number | boolean };

export type CaorenModParam = {
  key: string;
  name?: string;
  label: string;
  type: CaorenModParamType;
  defaultValue?: string | number | boolean;
  default?: string | number | boolean;
  placeholder?: string;
  helperText?: string;
  description?: string;
  min?: number;
  max?: number;
  step?: number;
  required?: boolean;
  options?: CaorenModOption[];
};

export type CaorenModModule = {
  id: string;
  name: string;
  title: string;
  label: string;
  command: string;
  aliases: string[];
  category: string;
  description: string;
  warning?: string;
  params: CaorenModParam[];
  args: CaorenModParam[];
  examples: string[];
  buildCommand: (values?: Record<string, unknown>) => string;
};

export type CaorenModCommandPayload = {
  moduleId?: string;
  id?: string;
  module?: string;
  values?: Record<string, unknown>;
  params?: Record<string, unknown>;
  args?: Record<string, unknown>;
};

export type CaorenModCommandResult = {
  ok: boolean;
  success: boolean;
  error?: string;
  command?: string;
  serverCommand?: string;
  module?: CaorenModModule;
  moduleId?: string;
  values?: Record<string, unknown>;
  label?: string;
  moduleTitle?: string;
  action?: string;
};

