function s(values: Record<string, unknown> | undefined, key: string, fallback = ''): string {
  const raw = values?.[key];
  if (raw === undefined || raw === null || raw === '') return fallback;
  return String(raw).trim();
}

function n(values: Record<string, unknown> | undefined, key: string, fallback: number): number {
  const raw = values?.[key];
  if (raw === undefined || raw === null || raw === '') return fallback;
  const parsed = Number(raw);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function b01(values: Record<string, unknown> | undefined, key: string, fallback: boolean): string {
  const raw = values?.[key];
  if (raw === undefined || raw === null || raw === '') return fallback ? '1' : '0';
  if (typeof raw === 'boolean') return raw ? '1' : '0';
  const text = String(raw).trim().toLowerCase();
  return text === '1' || text === 'true' || text === 'yes' || text === 'on' || text === '启用' ? '1' : '0';
}

function btf(values: Record<string, unknown> | undefined, key: string, fallback: boolean): string {
  const raw = values?.[key];
  if (raw === undefined || raw === null || raw === '') return fallback ? 'true' : 'false';
  if (typeof raw === 'boolean') return raw ? 'true' : 'false';
  const text = String(raw).trim().toLowerCase();
  return text === '1' || text === 'true' || text === 'yes' || text === 'on' || text === '启用' ? 'true' : 'false';
}

function target(values: Record<string, unknown> | undefined, fallback = 'all'): string {
  return s(values, 'target', fallback).toLowerCase();
}

function isOffTarget(value: string): boolean {
  const key = value.trim().toLowerCase();
  return key === '0' || key === 'off' || key === 'disable' || key === 'disabled' || key === '禁用';
}

function cmd(parts: Array<string | number | boolean>): string {
  return parts.map((part) => String(part).trim()).filter(Boolean).join(' ');
}

function pTeam(label = '目标', options: CaorenModOption[] = TEAM_OPTIONS): CaorenModParam {
  return { key: 'target', label, type: 'select', options, defaultValue: 'all', default: 'all', required: true };
}

function pNum(key: string, label: string, defaultValue: number, min?: number, max?: number, step = 1, helperText?: string): CaorenModParam {
  return { key, label, type: 'number', defaultValue, default: defaultValue, min, max, step, required: true, helperText };
}

function pText(key: string, label: string, defaultValue: string, helperText?: string): CaorenModParam {
  return { key, label, type: 'text', defaultValue, default: defaultValue, required: true, helperText };
}

function pBool(key: string, label: string, defaultValue: boolean, helperText?: string): CaorenModParam {
  return { key, label, type: 'boolean', defaultValue, default: defaultValue, required: false, helperText };
}

function makeModule(module: Omit<CaorenModModule, 'name' | 'label' | 'args'> & Partial<Pick<CaorenModModule, 'name' | 'label' | 'args'>>): CaorenModModule {
  return {
    ...module,
    name: module.name ?? module.id.toUpperCase(),
    label: module.label ?? module.title,
    args: module.args ?? module.params,
  };
}

